export function CustomCursor() {
  const [enabled, setEnabled] = useState(false);
  const cursorRef = useRef<HTMLDivElement>(null);
  const monogramRef = useRef<HTMLDivElement>(null);
  const labelRef = useRef<HTMLDivElement>(null);
  const modeRef = useRef<CursorMode>('default');

  useEffect(() => {
    const mql = window.matchMedia('(hover: hover) and (pointer: fine)');
    const update = () => setEnabled(mql.matches);
    update();
    mql.addEventListener('change', update);
    return () => mql.removeEventListener('change', update);
  }, []);

  useEffect(() => {
    if (!enabled) return;
    const el = cursorRef.current;
    const monogram = monogramRef.current;
    const label = labelRef.current;
    if (!el || !monogram || !label) return;

    gsap.set(el, { xPercent: -50, yPercent: -50, opacity: 0 });
    gsap.set(monogram, { opacity: 0.7, scale: 1 });
    gsap.set(label, { opacity: 0, scale: 1 });

    const xTo = gsap.quickTo(el, 'x', { duration: 0.35, ease: 'power3.out' });
    const yTo = gsap.quickTo(el, 'y', { duration: 0.35, ease: 'power3.out' });

    let visible = false;

    const setMode = (next: CursorMode) => {
      if (next === modeRef.current) return;
      modeRef.current = next;

      const monoOpacity =
        next === 'view' ? 0 : next === 'text' ? 0.4 : 0.7;
      const monoScale = next === 'cta' ? 1.2 : 1;
      const labelOpacity = next === 'view' ? 1 : 0;
      const labelScale = next === 'view' ? 1 : 0.9;

      gsap.to(monogram, {
        opacity: monoOpacity,
        scale: monoScale,
        duration: 0.25,
        ease: 'power2.out',
      });
      gsap.to(label, {
        opacity: labelOpacity,
        scale: labelScale,
        duration: 0.25,
        ease: 'power2.out',
      });
    };

    const onMove = (e: MouseEvent) => {
      xTo(e.clientX);
      yTo(e.clientY);

      if (!visible) {
        visible = true;
        gsap.to(el, { opacity: 1, duration: 0.2 });
      }

      const target = e.target as HTMLElement | null;
      if (!target) {
        setMode('default');
        return;
      }

      const tagged = target.closest<HTMLElement>('[data-cursor]');
      if (tagged) {
        const value = tagged.dataset.cursor as CursorMode | undefined;
        if (value === 'view' || value === 'cta' || value === 'text') {
          setMode(value);
          return;
        }
      }

      if (target.closest('button, a, [role="button"], input, textarea, select, label')) {
        setMode('cta');
        return;
      }

      if (TEXT_TAGS.has(target.tagName)) {
        setMode('text');
        return;
      }

      setMode('default');
    };

    const onLeave = () => {
      visible = false;
      gsap.to(el, { opacity: 0, duration: 0.2 });
    };

    const onEnter = () => {
      // Re-show on next mousemove
    };

    window.addEventListener('mousemove', onMove);
    document.documentElement.addEventListener('mouseleave', onLeave);
    document.documentElement.addEventListener('mouseenter', onEnter);

    return () => {
      window.removeEventListener('mousemove', onMove);
      document.documentElement.removeEventListener('mouseleave', onLeave);
      document.documentElement.removeEventListener('mouseenter', onEnter);
    };
  }, [enabled]);

  if (!enabled) return null;

  return (
    <div
      ref={cursorRef}
      aria-hidden="true"
      style={{
        position: 'fixed',
        top: 0,
        left: 0,
        width: 30,
        height: 30,
        pointerEvents: 'none',
        zIndex: 9999,
        mixBlendMode: 'normal',
        willChange: 'transform',
      }}
    >
      <div
        ref={monogramRef}
        style={{
          position: 'absolute',
          inset: 0,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          willChange: 'opacity, transform',
        }}
      >
        <NLMonogram size={30} />
      </div>
      <div
        ref={labelRef}
        style={{
          position: 'absolute',
          inset: 0,
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          fontFamily: '"Playfair Display", Georgia, serif',
          fontSize: 14,
          color: '#EBEBE5',
          letterSpacing: '0.02em',
          willChange: 'opacity, transform',
        }}
      >
        View
      </div>
    </div>
  );
}
